const data = $input.first().json;

// --- Defensive validation ---
if (!data || typeof data !== 'object') {
  throw new Error('Open-Meteo response is null or not an object.');
}
if (!data.daily || typeof data.daily !== 'object') {
  throw new Error('Open-Meteo response missing "daily" field.');
}
if (!data.current_weather || typeof data.current_weather !== 'object') {
  throw new Error('Open-Meteo response missing "current_weather" field.');
}
const requiredArrays = ['temperature_2m_max','temperature_2m_min','apparent_temperature_max','apparent_temperature_min','precipitation_sum','windspeed_10m_max','weathercode','time'];
for (const key of requiredArrays) {
  if (!Array.isArray(data.daily[key]) || data.daily[key].length === 0) {
    throw new Error(`Open-Meteo daily.${key} is missing or empty.`);
  }
}

// --- Date validation against today in America/New_York ---
const todayNY = new Date().toLocaleDateString('en-CA', { timeZone: 'America/New_York' }); // YYYY-MM-DD
const apiDate = data.daily.time[0];
const dateMismatch = apiDate !== todayNY;
if (dateMismatch) {
  console.warn(`Date mismatch: API returned ${apiDate}, expected ${todayNY}. Possible timezone edge case or API caching.`);
}

const weatherCodeMap = {
  0: 'Clear sky ☀️',
  1: 'Mainly clear 🌤️',
  2: 'Partly cloudy ⛅',
  3: 'Overcast ☁️',
  45: 'Fog 🌫️',
  48: 'Icy fog 🌫️❄️',
  51: 'Light drizzle 🌦️',
  53: 'Moderate drizzle 🌦️',
  55: 'Dense drizzle 🌧️',
  61: 'Slight rain 🌧️',
  63: 'Moderate rain 🌧️',
  65: 'Heavy rain 🌧️',
  71: 'Slight snow 🌨️',
  73: 'Moderate snow 🌨️',
  75: 'Heavy snow ❄️🌨️',
  77: 'Snow grains 🌨️',
  80: 'Slight showers 🌦️',
  81: 'Moderate showers 🌧️',
  82: 'Violent showers ⛈️',
  85: 'Slight snow showers 🌨️',
  86: 'Heavy snow showers ❄️',
  95: 'Thunderstorm ⛈️',
  96: 'Thunderstorm with hail ⛈️🌨️',
  99: 'Thunderstorm with heavy hail ⛈️❄️'
};

const daily = data.daily;
const current = data.current_weather;

const tempMax = daily.temperature_2m_max[0];
const tempMin = daily.temperature_2m_min[0];
const feelsMax = daily.apparent_temperature_max[0];
const feelsMin = daily.apparent_temperature_min[0];
const precip = daily.precipitation_sum[0];
const windMax = daily.windspeed_10m_max[0];
const weatherCode = daily.weathercode[0];
const currentTemp = current.temperature;
const currentWind = current.windspeed;
const date = daily.time[0];

const conditionDesc = weatherCodeMap[weatherCode] || `Code ${weatherCode}`;

// Freezing checks
const isHardFreeze = tempMin <= 28;
const isFreezing = tempMin <= 32;
const isFeelsFreezing = feelsMin <= 32;
const isFrostRisk = tempMin <= 36;

let freezeAlertHtml = '';
let freezeAlertText = '';
let hasFreezeAlert = false;
let alertSeverity = 'none';

if (isHardFreeze) {
  hasFreezeAlert = true;
  alertSeverity = 'hard_freeze';
  freezeAlertHtml = `<div style="background:#8B0000;color:#fff;padding:16px;border-radius:8px;margin-bottom:16px;font-size:18px;font-weight:bold;">🚨❄️ HARD FREEZE WARNING ❄️🚨<br/>Low of ${tempMin}°F — Pipes may freeze! Take precautions immediately.</div>`;
  freezeAlertText = `🚨❄️ HARD FREEZE WARNING ❄️🚨\nLow of ${tempMin}°F — Pipes may freeze! Take precautions immediately.\n\n`;
} else if (isFreezing) {
  hasFreezeAlert = true;
  alertSeverity = 'freeze';
  freezeAlertHtml = `<div style="background:#00008B;color:#fff;padding:16px;border-radius:8px;margin-bottom:16px;font-size:18px;font-weight:bold;">❄️ FREEZE ALERT ❄️<br/>Low of ${tempMin}°F — Temperatures at or below freezing tonight!</div>`;
  freezeAlertText = `❄️ FREEZE ALERT ❄️\nLow of ${tempMin}°F — Temperatures at or below freezing tonight!\n\n`;
} else if (isFeelsFreezing) {
  hasFreezeAlert = true;
  alertSeverity = 'wind_chill';
  freezeAlertHtml = `<div style="background:#4169E1;color:#fff;padding:16px;border-radius:8px;margin-bottom:16px;font-size:16px;font-weight:bold;">🥶 WIND CHILL FREEZE ALERT 🥶<br/>Feels as low as ${feelsMin}°F — Dress warmly, wind chill is dangerous!</div>`;
  freezeAlertText = `🥶 WIND CHILL FREEZE ALERT 🥶\nFeels as low as ${feelsMin}°F — Dress warmly!\n\n`;
} else if (isFrostRisk) {
  hasFreezeAlert = true;
  alertSeverity = 'frost';
  freezeAlertHtml = `<div style="background:#708090;color:#fff;padding:14px;border-radius:8px;margin-bottom:16px;font-size:15px;font-weight:bold;">⚠️ FROST RISK ⚠️<br/>Low of ${tempMin}°F — Near-freezing conditions possible.</div>`;
  freezeAlertText = `⚠️ FROST RISK ⚠️\nLow of ${tempMin}°F — Near-freezing conditions possible.\n\n`;
}

// Date mismatch visible warning banner
let dateMismatchHtml = '';
let dateMismatchText = '';
if (dateMismatch) {
  dateMismatchHtml = `<div style="background:#FFD700;color:#333;padding:12px;border-radius:8px;margin-bottom:16px;font-size:14px;font-weight:bold;">⚠️ Date mismatch detected — API returned ${apiDate}, expected ${todayNY}. Data may be from a different date.</div>`;
  dateMismatchText = `⚠️ Date mismatch detected — API returned ${apiDate}, expected ${todayNY}. Data may be from a different date.\n\n`;
}

// Subject line reflects severity
let subjectPrefix;
if (alertSeverity === 'hard_freeze') {
  subjectPrefix = `🚨 HARD FREEZE WARNING`;
} else if (alertSeverity === 'freeze') {
  subjectPrefix = `❄️ FREEZE ALERT`;
} else if (alertSeverity === 'wind_chill') {
  subjectPrefix = `🥶 WIND CHILL FREEZE ALERT`;
} else if (alertSeverity === 'frost') {
  subjectPrefix = `⚠️ FROST RISK`;
} else {
  subjectPrefix = `🌆 NYC Weather`;
}

const subject = `${subjectPrefix} — NYC Weather: High ${tempMax}°F / Low ${tempMin}°F | ${conditionDesc}`;

const htmlBody = `
<html>
<body style="font-family:Arial,sans-serif;max-width:600px;margin:auto;padding:20px;">
  <h1 style="color:#1a1a2e;">🌆 NYC Daily Weather Summary</h1>
  <p style="color:#666;">📅 ${date} | New York City</p>
  <hr/>
  ${dateMismatchHtml}
  ${freezeAlertHtml}
  <table style="width:100%;border-collapse:collapse;margin-top:12px;">
    <tr style="background:#f0f4ff;">
      <td style="padding:10px;font-weight:bold;">🌡️ Temperature at 7AM</td>
      <td style="padding:10px;">${currentTemp}°F</td>
    </tr>
    <tr>
      <td style="padding:10px;font-weight:bold;">🔼 High</td>
      <td style="padding:10px;">${tempMax}°F <span style="color:#888;">(Feels like ${feelsMax}°F)</span></td>
    </tr>
    <tr style="background:#f0f4ff;">
      <td style="padding:10px;font-weight:bold;">🔽 Low</td>
      <td style="padding:10px;${tempMin <= 32 ? 'color:#00008B;font-weight:bold;' : ''}">${tempMin}°F <span style="color:#888;">(Feels like ${feelsMin}°F)</span>${tempMin <= 32 ? ' ❄️' : ''}</td>
    </tr>
    <tr>
      <td style="padding:10px;font-weight:bold;">🌤️ Conditions</td>
      <td style="padding:10px;">${conditionDesc}</td>
    </tr>
    <tr style="background:#f0f4ff;">
      <td style="padding:10px;font-weight:bold;">💨 Max Wind Speed</td>
      <td style="padding:10px;">${windMax} mph (Current: ${currentWind} mph)</td>
    </tr>
    <tr>
      <td style="padding:10px;font-weight:bold;">🌧️ Precipitation</td>
      <td style="padding:10px;">${precip} inches</td>
    </tr>
  </table>
  <hr style="margin-top:20px;"/>
  <p style="color:#aaa;font-size:12px;">Data sourced from Open-Meteo (open-meteo.com) — Free weather API</p>
</body>
</html>
`;

const plainText = `NYC Daily Weather Summary\n========================\nDate: ${date}\n\n${dateMismatchText}${freezeAlertText}Temperature at 7AM: ${currentTemp}°F\nHigh: ${tempMax}°F (Feels like ${feelsMax}°F)\nLow: ${tempMin}°F (Feels like ${feelsMin}°F)${tempMin <= 32 ? ' ❄️ FREEZING' : ''}\nConditions: ${conditionDesc}\nMax Wind: ${windMax} mph (Current: ${currentWind} mph)\nPrecipitation: ${precip} inches\n\nData: open-meteo.com`;

return [{
  json: {
    subject,
    htmlBody,
    plainText,
    hasFreezeAlert,
    alertSeverity,
    dateMismatch,
    tempMax,
    tempMin,
    feelsMax,
    feelsMin,
    currentTemp,
    currentWind,
    windMax,
    precip,
    conditionDesc,
    date
  }
}];
